const lead = $input.first().json.body;

let score = 0;
let reasons = [];

if (["100-200", "200-500", "500-1000"].includes(lead.company_size)) {
  score += 25;
  reasons.push("Company size suggests a real sales/ops team with enough volume.");
} else if (lead.company_size === "11-50") {
  score += 10;
  reasons.push("Smaller company, possible fit but likely lower urgency.");
} else {
  reasons.push("Very small company, likely limited buying capacity.");
}

if (["VP", "Director", "Head", "Founder"].some(title => lead.job_title.includes(title))) {
  score += 25;
  reasons.push("Lead has decision-maker or senior influencer title.");
}

if (["$50k-$100k", "$25k-$50k"].includes(lead.budget_range)) {
  score += 25;
  reasons.push("Budget range indicates potential buying capacity.");
} else {
  reasons.push("Budget appears limited.");
}

if (["Next 30 days", "Next 60 days", "This quarter"].includes(lead.timeline)) {
  score += 25;
  reasons.push("Timeline suggests near-term intent.");
} else {
  reasons.push("Timeline is vague or long-term.");
}

let fit_level = "Low";
let recommended_next_action = "Keep in CRM, but do not prioritize immediate sales time.";

if (score >= 75) {
  fit_level = "High";
  recommended_next_action = "Prioritize for sales outreach within 24 hours.";
} else if (score >= 40) {
  fit_level = "Medium";
  recommended_next_action = "Add to nurture sequence and review manually.";
}

const draft_follow_up_email = `Subject: Quick idea for ${lead.company}

Hi ${lead.first_name},

I noticed that your team may be dealing with: ${lead.pain_point}.

A simple lead qualification workflow could help your team quickly identify which inbound leads need immediate sales attention, which leads should go into nurture, and which ones are lower priority.

This looks like the kind of workflow where faster lead qualification could save your team meaningful time.

Would you be open to a quick 15-minute conversation this week?

Best,
Himanshu`;

return [
  {
    json: {
      ...lead,
      lead_score: score,
      fit_level,
      qualification_reason: reasons.join(" "),
      recommended_next_action,
      draft_follow_up_email
    }
  }
];
